-- Wall Drill ISO — Split Shin Angle Hold (wall-drill-split-shin-hold)
UPDATE coaching.exercise SET
  name = 'Wall Drill ISO — Split Shin Angle Hold',
  description = 'Athlete leans into a wall with hands at shoulder height, one foot forward and one back in a split stance. Front shin stays near vertical, back leg extends with heel lifted, ankle dorsiflexed, and torso in a straight sprint line. Hold the shape without bouncing or collapsing.',
  card_summary = 'Static wall-supported sprint posture hold that teaches forward lean, split-shin angles, dorsiflexion, and triple extension without moving.',
  coach_language = 'Use as the first wall drill to teach sprint posture, split-shin angles, and dorsiflexion before dynamic wall exchanges or upright A-drills.',
  athlete_language = 'Lean into the wall, straight line from head to heel, front shin up, back toe up, and hold it tight.',
  movement_family = 'Locomotion & sprint mechanics',
  primary_phase_key = 'movement_intelligence',
  phase_subrole = 'locomotion_sprint_mechanics',
  primary_order_slot = 'sprint_iso',
  default_sets = 2,
  default_reps = NULL,
  default_work_seconds = 5,
  default_rest_seconds = 20,
  est_seconds_per_set = 20,
  movement_requirements = '{"primary_joint_actions":["ankle_dorsiflexion","hip_extension","knee_flexion"],"primary_tissues":["calves","hip_flexors","core"],"breathing_demand":"nasal","balance_demand":"stable","impact_level":0,"prerequisites":[]}'::jsonb,
  coaching_execution = '{"movement_description":"Wall lean with split stance — front shin near vertical, back leg long with dorsiflexed ankle, straight body line.","setup":["Stand arm-length from a sturdy wall.","Hands at shoulder height, arms straight.","Split stance with front foot flat and back foot on ball of foot.","Choose lead leg for first hold."],"execution_steps":["Lean forward until body forms a straight line through ears, shoulders, hips, and back heel.","Pull front toes up; keep front shin near vertical.","Extend back leg with heel up and ankle stiff.","Hold without bouncing or sinking at the hips.","Reset and repeat on the other leg."],"breathing_cues":["Quiet nasal breathing.","Stay relaxed through face and neck.","Do not brace breath until failure."],"coach_cues":["Straight line.","Front shin up.","Back toe up.","Hips square.","Push the wall away with your hands."],"athlete_cues":["Lean tall.","Split shape.","Toes up.","Hold steady."],"common_faults":["Standing too upright.","Front foot too far forward with heel off ground.","Back ankle collapsed or toe pointed down.","Broken line at hips or low back.","Holding breath and shaking instead of organizing posture."],"stop_signs":["Calf cramping.","Knee or ankle pain.","Dizziness from excessive lean.","Athlete cannot maintain square hips."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Wall Body-Line Drill","Ankle Dorsiflexion Prep","Glute Bridge","A-March — Technical Version"],"pairs_well_after":["Wall Drill March","Wall Drill Switch","A-March — Technical Version"],"good_for_sessions":["sprint_prep","general_warmup"],"avoid_before":["Max sprinting if athlete cannot hold split-shin shape","Wall switch before ISO is stable"],"avoid_after":[],"do_not_use_when":["Acute calf or Achilles pain","No stable wall surface","Balance unsafe without support"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["SimpliFaster Wall Drill Progressions","ALTIS Sprint Posture — Wall Lean Series"],"internal_notes":["Hold both lead-leg positions before progressing to march."]}'::jsonb,
  updated_at = now()
WHERE slug = 'wall-drill-split-shin-hold';

