  coaching_execution = '{"movement_description":"Wall lean with alternating knee drives — toe up, heel under knee, quiet hip exchange.","setup":["Same wall setup as wall ISO.","Hands on wall at shoulder height.","Start in split stance with straight body line."],"execution_steps":["Drive front knee up to hip height or appropriate range.","Pull toe up and keep shin vertical at top.","Exchange legs smoothly without losing lean.","Extend back leg fully with toe up on each stance.","Complete prescribed marches per side or total reps."],"breathing_cues":["Rhythmic breathing with leg exchange.","Stay relaxed through shoulders."],"coach_cues":["Knee up, toe up.","Quiet feet.","Straight line.","Exchange under the hip.","Slow before fast."],"athlete_cues":["March tall.","Cycle legs.","Toe up.","Stay on the wall."],"common_faults":["Losing forward lean.","Kicking forward instead of lifting knee up.","Toe pointing down.","Hips rotating or dropping.","Marching too fast before shape is clean."],"stop_signs":["Hip flexor pinching.","Loss of posture every exchange.","Calf cramping.","Knee pain."]}'::jsonb,
