  coaching_execution = '{"movement_description":"Fall forward from standing, catch in split sprint stance, hold push angle without running out.","setup":["Clear lane with soft surface.","Stand tall on start line.","Coach at side for beginners.","Choose lead leg before each attempt."],"execution_steps":["Lean forward as one stiff unit from ankles.","Allow body to fall until near balance limit.","Catch with quick split stance — front shin up, back toe up.","Set arms in sprint-ready position.","Hold 3–5 seconds or freeze and reset without sprinting away."],"breathing_cues":["Exhale on catch.","Quiet breathing during hold."],"coach_cues":["Fall as one piece.","Catch with split shape.","Front shin up.","Push the ground away.","Freeze — do not run yet."],"athlete_cues":["Fall tall.","Catch shape.","Hold angles.","Freeze."],"common_faults":["Breaking at the hips only instead of whole-body lean.","Taking multiple stutter steps before catching.","Front foot landing too far ahead.","Running out immediately instead of holding.","Back ankle collapsed."],"stop_signs":["Falling uncontrolled.","Knee or ankle pain on catch.","Dizziness.","Athlete cannot freeze without extra steps."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Two-Point Start Walk-In","A-March — Technical Version","Arm Action Drill","Output acceleration work"],"pairs_well_after":["Wall Drill ISO — Split Shin Angle Hold","Wall Body-Line Drill","Two-Point Start Walk-In prep"],"good_for_sessions":["sprint_prep","general_warmup"],"avoid_before":["Repeated max-effort starts if athlete cannot hold caught position","Conditioning sprints after drill"],"avoid_after":[],"do_not_use_when":["Balance unsafe","Acute calf/Achilles pain","Athlete runs out uncontrollably every rep"]}'::jsonb,
