UPDATE coaching.exercise_scaling_profile sp SET
  load_guidance = v.guidance,
  gender_specific_notes = CASE WHEN 'youth_beginner' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
FROM (VALUES
  ('wall-drill-split-shin-hold', 'Excellent first wall drill. Use shorter holds and less lean until athlete finds the line.', 'No default male/female dosage split. Scale by training age, sprint experience, mobility, balance, symptoms, and prerequisites.'),
  ('wall-drill-march', 'Count marches out loud; use fewer reps until rhythm is smooth.', 'No default male/female dosage split. Scale by training age, sprint experience, mobility, balance, symptoms, and prerequisites.'),
  ('wall-drill-switch', 'Use short distances, simple cues, wall support, and clear shape goals.', 'No default male/female dosage split. Scale by training age, sprint experience, mobility, balance, symptoms, and prerequisites.'),
  ('a-march', 'March in place first with "knee up, toe up" rhythm game.', 'No default male/female dosage split. Scale by training age, sprint experience, mobility, balance, symptoms, and prerequisites.'),
  ('a-skip', 'Use slow skip rhythm games over 5–10 yards.', 'No default male/female dosage split. Scale by training age, sprint experience, mobility, balance, symptoms, and prerequisites.'),
  ('ankling-dribble-march', 'Stationary ankling or 5-yard dribbles before full 10 yards.', 'No default male/female dosage split. Scale by training age, sprint experience, mobility, balance, symptoms, and prerequisites.'),
  ('straight-leg-bound-march', 'Use short distances, simple cues, wall support, and clear shape goals.', 'No default male/female dosage split. Scale by training age, sprint experience, mobility, balance, symptoms, and prerequisites.'),
  ('falling-start-hold', 'Coach stands nearby; use shorter fall distance and hold-only reps.', 'No default male/female dosage split. Scale by training age, sprint experience, mobility, balance, symptoms, and prerequisites.'),
  ('two-point-start-walk-in', 'Use walk-in to 3 steps only; coach at shoulder for safety.', 'No default male/female dosage split. Scale by training age, sprint experience, mobility, balance, symptoms, and prerequisites.'),
  ('arm-action-drill', 'Seated drill with "cheek to pocket" call-and-response works well.', 'No default male/female dosage split. Scale by training age, sprint experience, mobility, balance, symptoms, and prerequisites.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE sp.exercise_id = e.id AND sp.cohort_key = 'youth_beginner';

