-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for athletic development.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('wall-drill-split-shin-hold', 'The wall ISO removes speed and lets the athlete feel correct split-shin angles, dorsiflexion, hip extension, and forward lean without compensation. Coaches can fix posture before adding rhythm or ground contacts.', 'Belongs in sprint_iso (233) — static posture reference before wall march/switch and upright sprint-mechanics drills.', 'First sprint-mechanics drill in Locomotion & Sprint Mechanics before wall march, switch, or upright marching progressions.', 'Sprint mechanics drills should sharpen posture, rhythm, foot strike, and acceleration shapes while the athlete is fresh enough to think, react, and stay organized. Do not become max-speed sprinting, repeated explosive starts, conditioning circuits, or sustained capacity work in Skill phase — those belong in Output or Sustained Capacity. ISO holds are posture teachers, not calf-burnout isometrics. Avoid long holds beyond Skill dose.', 'Regress to shorter holds, less lean, or higher hand placement; progress to wall march once shape is stable both sides.'),
  ('wall-drill-march', 'Wall march links static sprint posture to rhythmic leg cycling. The wall supports balance so the athlete can focus on knee height, dorsiflexion, and hip exchange without chasing speed.', 'Belongs in sprint_mechanics (234) — cyclical wall drill after ISO, before switch or upright marches.', 'After wall ISO hold when athlete can maintain split-shin angles and straight body line.', 'Sprint mechanics drills should sharpen posture, rhythm, foot strike, and acceleration shapes while the athlete is fresh enough to think, react, and stay organized. Do not become max-speed sprinting, repeated explosive starts, conditioning circuits, or sustained capacity work in Skill phase — those belong in Output or Sustained Capacity. Do not march fast or turn into conditioning. Skill dose is slow, coached exchanges.', 'Regress to ISO holds or fewer reps; progress to wall switch once each march is crisp.'),
  ('wall-drill-switch', 'Wall switch bridges slow marching to faster leg turnover. The wall stabilizes the athlete while they learn rapid hip exchange — the same timing demand as upright sprint drills without horizontal velocity.', 'Belongs in sprint_mechanics (234) — dynamic wall exchange after march, before A-skip or acceleration drills.', 'After wall ISO and wall march when athlete can maintain posture through cyclical exchanges.', 'Sprint mechanics drills should sharpen posture, rhythm, foot strike, and acceleration shapes while the athlete is fresh enough to think, react, and stay organized. Do not become max-speed sprinting, repeated explosive starts, conditioning circuits, or sustained capacity work in Skill phase — those belong in Output or Sustained Capacity. Count switches, not total ground contacts. Do not chase max cadence if posture breaks down.', 'Regress to wall march; progress to A-skip once switches stay tall and quiet.'),
  ('a-march', 'The A-March isolates upright sprint posture, knee lift, recovery mechanics, dorsiflexion, and arm-leg coordination without the speed demand of A-skip or sprinting. It is the standard bridge from wall drills to rhythmic upright work.', 'Belongs in technical_march (235) — coached upright march in Skill phase; Prepare & Access uses the same slug with marching_mechanics intent at lower RPE.', 'After wall drills or Prepare & Access A-March bridge when athlete needs coached upright sprint mechanics in Skill phase.', 'Sprint mechanics drills should sharpen posture, rhythm, foot strike, and acceleration shapes while the athlete is fresh enough to think, react, and stay organized. Do not become max-speed sprinting, repeated explosive starts, conditioning circuits, or sustained capacity work in Skill phase — those belong in Output or Sustained Capacity. Do not march fast for conditioning. Skill A-March is technical, fresh, and slow-to-moderate tempo.', 'Regress to march-in-place or wall march; progress to A-skip once rhythm and foot strike are clean.'),
  ('a-skip', 'A-skip adds a short flight phase and elastic rebound to marching mechanics, teaching the rhythm and stiffness used in acceleration and upright sprinting without full max-velocity demand.', 'Belongs in sprint_rhythm (236) — rhythmic skip after technical march, before faster Output work.', 'After A-March and wall switch when athlete can maintain posture through a skip rhythm.', 'Sprint mechanics drills should sharpen posture, rhythm, foot strike, and acceleration shapes while the athlete is fresh enough to think, react, and stay organized. Do not become max-speed sprinting, repeated explosive starts, conditioning circuits, or sustained capacity work in Skill phase — those belong in Output or Sustained Capacity. Do not turn A-skip into a conditioning lap or max-speed sprint. Keep distance short and posture crisp.', 'Regress to A-March or march-in-place skip pattern; shorten distance if contacts get heavy.'),
  ('ankling-dribble-march', 'Ankling isolates the foot and ankle contribution to sprinting — dorsiflexion, quick ground contact, and stiffness — without large knee drive that can hide poor foot strike habits.', 'Belongs in foot_strike_skill (237) — ankle rhythm drill before A-skip or acceleration contacts.', 'After posture and march work when athlete needs foot-strike and ankle rhythm before A-skip or sprinting.', 'Sprint mechanics drills should sharpen posture, rhythm, foot strike, and acceleration shapes while the athlete is fresh enough to think, react, and stay organized. Do not become max-speed sprinting, repeated explosive starts, conditioning circuits, or sustained capacity work in Skill phase — those belong in Output or Sustained Capacity. Do not use high rep volume that fatigues shins before sprint or jump work. Skill dose is short and quiet.', 'Regress to stationary ankling or shorter distance; progress to A-skip once contacts stay light.'),
  ('straight-leg-bound-march', 'Straight-leg bounds teach the frontside swing and pawing action of upright sprinting — hamstring reach, dorsiflexion, and quick pull-back — complementing knee-lift drills like A-March and A-skip.', 'Belongs in frontside_mechanics (238) — pawing / straight-leg prep before faster upright sprint work.', 'After basic march and foot-strike work when athlete needs frontside / pawing awareness before faster sprint drills.', 'Sprint mechanics drills should sharpen posture, rhythm, foot strike, and acceleration shapes while the athlete is fresh enough to think, react, and stay organized. Do not become max-speed sprinting, repeated explosive starts, conditioning circuits, or sustained capacity work in Skill phase — those belong in Output or Sustained Capacity. Do not turn into max-effort bounding or hamstring overload. Skill dose is controlled march/bound height.', 'Regress to straight-leg march without bound; shorten distance if hamstrings feel excessive strain.'),
  ('falling-start-hold', 'The falling start teaches the athlete to find acceleration lean and split-shin angles from gravity rather than guessing. Holding the caught position builds the push angle used in first-step acceleration.', 'Belongs in acceleration_position (239) — postural acceleration shape before walk-in or explosive starts.', 'Before walk-in starts or explosive acceleration when athlete needs to feel push angle and body line from a lean.', 'Sprint mechanics drills should sharpen posture, rhythm, foot strike, and acceleration shapes while the athlete is fresh enough to think, react, and stay organized. Do not become max-speed sprinting, repeated explosive starts, conditioning circuits, or sustained capacity work in Skill phase — those belong in Output or Sustained Capacity. Do not sprint out of every rep or repeat explosive starts for conditioning. Skill dose is hold or short catch-and-freeze.', 'Regress to wall ISO or shorter fall; progress to two-point walk-in once hold is stable.'),
  ('two-point-start-walk-in', 'Walk-in starts reduce the chaos of explosive block starts while still teaching projection, shin angles, and progressive rise. Athletes learn first-step mechanics they can later express at higher intent in Output.', 'Belongs in acceleration_entry (240) — controlled start entry after falling start posture work.', 'After falling start hold when athlete can organize push angle and first-step mechanics under control.', 'Sprint mechanics drills should sharpen posture, rhythm, foot strike, and acceleration shapes while the athlete is fresh enough to think, react, and stay organized. Do not become max-speed sprinting, repeated explosive starts, conditioning circuits, or sustained capacity work in Skill phase — those belong in Output or Sustained Capacity. Do not turn into repeated max-effort 20-yard sprints or conditioning. Skill dose is 3–5 submax attempts with coaching.', 'Regress to falling start hold only; shorten distance or use walk-in without run-out for beginners.'),
  ('arm-action-drill', 'Arm action contributes to rhythm, balance, and ground reaction forces in sprinting. Isolating the arms lets athletes fix crossover, shoulder tension, and range without leg fatigue masking errors.', 'Belongs in arm_action (240) — isolated arm drive supporting march, skip, and acceleration drills.', 'Alongside march, skip, or start drills when arm action breaks down or needs isolated coaching.', 'Sprint mechanics drills should sharpen posture, rhythm, foot strike, and acceleration shapes while the athlete is fresh enough to think, react, and stay organized. Do not become max-speed sprinting, repeated explosive starts, conditioning circuits, or sustained capacity work in Skill phase — those belong in Output or Sustained Capacity. Do not perform high-rep arm burnouts or band-resisted endurance work in Skill. Short technical sets only.', 'Regress to seated arms-only; progress to standing march with same arm cueing.')
) AS v(slug, why_works, why_here, best_placement, misuse, scale_guidance)
JOIN coaching.exercise e ON e.slug = v.slug
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_works = EXCLUDED.why_it_works,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();

-- Sprint-mechanics cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'skill_sprint_readiness',
  NULL,
  'Locomotion & Sprint Mechanics without pre-fatigue',
  'Sprint-mechanics drills should sharpen posture, rhythm, foot strike, and acceleration shapes while athletes are fresh — not become max-speed sprinting, conditioning circuits, or repeated explosive starts in Skill.',
  'Sprint mechanics cards teach wall posture, hip exchange, marching rhythm, foot strike, acceleration lean, start entry, and arm action before Output speed work.',
  'Sloppy sprint drills under fatigue transfer into overstriding, toe-down contacts, and poor first steps. Skill phase is for learning the pattern; Output expresses it fast.',
  'Cap wall ISO holds at ~8s per side, keep wall switches crisp and low volume, regress to ISO or A-March when posture breaks, place sprint mechanics before Output speed blocks, and move timed or max-intent work to Output.',
  'Do not assign max accelerations, timed competitive starts, high-volume wall switches, or conditioning-style footwork in Skill — reduce dose or change phase intent.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
